$$, $$5ac8b1ec016d7a02224552b6d08f235cd0fa7c01722d500bcb1d3ad5958c00c5$$, $${"A": "7f9bf946a9b2d104d3bf8c3c455b0a120e39c9e4b61ecce4d1b6fda938c3bc28", "C": "7c0ee9d98304a9488003ab1188d244c6b175af435fb37a855e408c7a4fb86975", "D": "0ad1ff6e0aa54592f91c03a4996ad031fcc8711d61d14bbd288093fa42ccc782"}$$::jsonb, $$Budget J-Books/FY26/Navy/RDTEN_BA5_Book.pdf$$, 109, $$2026-05-10T04:03:06.372628+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603208N$$, 2026, $$This program element provides for design, development, integration and test of various pre and post production platform improvements for Naval Undergraduate Flight
Training Systems which include T-45, T-6, T-44, TH-57, TH-73A, T-54, and T-45 Follow-On: Undergraduate Jet Training System (UJTS). Continued development
engineering for improvements in reliability, maintainability, and safety are required to ensure maximum benefit is achieved to provide effective cost of ownership
and availability of aircraft to meet Chief of Naval Air Training (CNATRA) student training requirements. Specific efforts include: T-45, T-6, TH-57, T-44, T-54, and
TH-73A Training System Improvements such as development and sustainment engineering change proposals (ECPs), avionics reliability and modernization, corrosion
prevention ECPs, obsolescence ECPs, T-45 Retrofit Integration Testing (RIT), and new solutions required to meet evolving fleet training requirements; T-45 and T-6
Physiological Episode (PE) mitigation analysis; New Start T-6B Avionics Modernization; and T-45 Follow-On UJTS development.

 This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects conducting engineering and manufacturing
 development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, $$T-45 and T-6 Physiological Episode (PE) Mitigation:
Efforts will provide for studies and development efforts to address mitigation of the T-45 and T-6 physiological episodes.

